// Time:  O(n)
// Space: O(1)

class Solution {
public:
    string minRemoveToMakeValid(string s) {
        int count = 0;
        for (auto i = 0; i < s.size(); ++i) {
            if (s[i] == '(') {
                ++count;
            }
            if (s[i] == ')') {
                if (count) {
                    --count;
                } else {
                    s[i] = ' ';
                }
            }
        }
        if (count) {
            for (auto i = s.size() - 1; i >= 0; --i) {
                if (s[i] == '(') {
                    s[i] = ' ';
                    if (--count == 0) {
                        break;
                    }
                }
            }
        }
        s.erase(remove(s.begin(), s.end(), ' '), s.end());
        return s;
    }
};

# Time:  O(n)
# Space: O(n)

class Solution(object):
    def minRemoveToMakeValid(self, s):
        """
        :type s: str
        :rtype: str
        """
        result = list(s)
        count = 0
        for i, v in enumerate(result):
            if v == '(':
                count += 1
            elif v == ')':
                if count:
                    count -= 1
                else:
                    result[i] = ""
        if count:
            for i in reversed(xrange(len(result))):
                if result[i] == '(':
                    result[i] = ""
                    count -= 1
                    if not count:
                        break
        return "".join(result)
